LoadMgr={}function LoadMgr:Init()local a={}setmetatable(a,self)self.__index=self;self.Inst=a end;function LoadMgr:GetRes(b)if b==ESceneTypes.Entrance then return{'scenes/entrance/main'}elseif b==ESceneTypes.Lobby then return{'scenes/lobby/main'}elseif b==ESceneTypes.MJ then local c={'scenes/mj/effect_mj/main','scenes/mj/effect_mj/extend','scenes/mj/effect_mj/locallize','scenes/mj/mjtable'}if not Tools.IsWebGL()then table.insert(c,"yiman")end;return c elseif b==ESceneTypes.Spot then return{'docs/spots','scenes/spot/main'}elseif b==ESceneTypes.Amulet then return{'scenes/amulet/main','scenes/mj/mjtable','ui/amulet'}elseif b==ESceneTypes.Common then return{'ui/common/main','deco/illust_data','audio/audio_common'}elseif b==ESceneTypes.MajorActivity then return{"ui/marathon"}end;return{}end;function LoadMgr:LoadRes(b,d,e)local c=self:GetRes(b)LuaTools.LoadGroups(c,d,e)end;function LoadMgr:UnLoadRes(b)local c=self:GetRes(b)LuaTools.UnLoadGroups(c)end;function LoadMgr:LoadCommonResAfterLogin(d,e)local f={"spine/spineUI","scenes/lobby/main"}local g=GameMgr.Inst.account_data.avatar_id;local h=ExcelMgr.GetData("item_definition","skin",g)if not h then LogTool.Warning("LoadMgr","尝试加载看板角色语音时皮肤 id 异常：",g)LuaTools.LoadGroups(f,d,e)return end;local i=ExcelMgr.GetData('item_definition','character',h.character_id)if not i then LogTool.Warning("LoadMgr","尝试加载看板角色语音时角色 id 异常：",h.character_id)LuaTools.LoadGroups(f,d,e)return end;local j=ExcelMgr.GetData('voice','sound',i.sound)if not j or not j[1]then LogTool.Warning("LoadMgr","尝试加载看板角色语音时语音配置数据异常：",i.sound)LuaTools.LoadGroups(f,d,e)return end;table.insert(f,'audio/sound/'..i.sound_folder)LuaTools.LoadGroups(f,d,e)end